package com.example.bankingapp;

import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;

public class BankingActivity extends AppCompatActivity {

    private TextView accountBalanceTextView;
    private EditText amountEditText;
    private Button depositButton;
    private Button withdrawButton;

    private double balance = 1000.0; // Initial balance

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        accountBalanceTextView = findViewById(R.id.account_balance_text_view);
        amountEditText = findViewById(R.id.amount_edit_text);
        depositButton = findViewById(R.id.deposit_button);
        withdrawButton = findViewById(R.id.withdraw_button);

        updateAccountBalance();

        depositButton.setOnClickListener(v -> {
            double amount = getAmountFromInput();
            if (amount > 0) {
                balance += amount;
                updateAccountBalance();
                Toast.makeText(BankingActivity.this, "Deposited $" + amount, Toast.LENGTH_SHORT).show();
            } else {
                Toast.makeText(BankingActivity.this, "Invalid amount", Toast.LENGTH_SHORT).show();
            }
        });

        withdrawButton.setOnClickListener(v -> {
            double amount = getAmountFromInput();
            if (amount > 0 && balance >= amount) {
                balance -= amount;
                updateAccountBalance();
                Toast.makeText(BankingActivity.this, "Withdrew $" + amount, Toast.LENGTH_SHORT).show();
            } else {
                Toast.makeText(BankingActivity.this, "Insufficient funds or invalid amount", Toast.LENGTH_SHORT).show();
            }
        });
    }

    private void updateAccountBalance() {
        accountBalanceTextView.setText("Current Balance: $" + balance);
    }

    private double getAmountFromInput() {
        try {
            return Double.parseDouble(amountEditText.getText().toString());
        } catch (NumberFormatException e) {
            return 0.0;
        }
    }
}